import './List.scss';

import type { FC } from 'react';
import React, { useMemo } from 'react';

import { classNames } from '../../helpers/classnames';
import type { ListProps } from './List.types';

export const List: FC<ListProps> = ({ className, type = 'ul', ...props }) => {
	const classes = useMemo(() => classNames('dsb_list', className), [className]);

	return type === 'ul' ? (
		<ul data-testid="List" {...props} className={classes} />
	) : (
		<ol data-testid="List" {...props} className={classes} />
	);
};
